+		test_adler32(buf_start, 5553, initial_value);
+		test_adler32(buf_start, rand() % 32769, initial_value);
+		buf_start[rand() % 32768] = 0xFE;
+	}
+
+	free_guarded_buffer(buf_start, buf_end);
+	return 0;
+}

